index fdef49e310f8..002465aef46c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -826,10 +826,13 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
     }

     Constant *C;
-    if (match(Src, m_OneUse(m_LShr(m_Value(X), m_ImmConstant(C))))) {
+    if (match(Src, m_LShr(m_Value(X), m_ImmConstant(C)))) {
       // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0
+      // If C' is a single-bit non-negative constant, canonicalize to equality.
       Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
-      Value *MaskC = Builder.CreateShl(One, C);
+      Constant *MaskC = ConstantExpr::get(Instruction::Shl, One, C);
+      if (match(MaskC, m_Power2()))
+        return new ICmpInst(ICmpInst::ICMP_EQ, X, C);
       Value *And = Builder.CreateAnd(X, MaskC);
       return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
     }
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 550f095b26ba..bd015f9e566d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1292,6 +1292,15 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   const APInt *C;
   unsigned BitWidth = Ty->getScalarSizeInBits();

+  // lshr C, X where C is a single-bit non-negative constant can be converted
+  // to a compare when we only care about the low bit of the result (i1 type).
+  if (Ty->isIntOrIntVectorTy(1)) {
+    const APInt *C0;
+    if (match(Op0, m_APInt(C0)) && C0->isPowerOf2() && !C0->isNegative())
+      return new ICmpInst(ICmpInst::ICMP_EQ, Op1,
+                          ConstantInt::get(Op1->getType(), C0->logBase2()));
+  }
+
   // (iN (~X) u>> (N - 1)) --> zext (X > -1)
   if (match(Op0, m_OneUse(m_Not(m_Value(X)))) &&
       match(Op1, m_SpecificIntAllowPoison(BitWidth - 1)))

